class Solution:
    def largestNumber(self, nums: List[int]) -> str:
        from functools import cmp_to_key
        def cmp(a, b):
            x, y = str(a)+str(b), str(b)+str(a)
            return (x > y) - (x < y)
        nums.sort(key=cmp_to_key(cmp), reverse=True)
        res = ''.join(map(str, nums))
        return '0' if res[0] == '0' else res

