class Solution {
public:
    string largestNumber(vector<int>& nums) {
        vector<string> s;
        for (int x : nums) s.push_back(to_string(x));
        sort(s.begin(), s.end(), [](const string& a, const string& b) {
            return a + b > b + a;
        });
        string res;
        for (auto& t : s) res += t;
        return res[0] == '0' ? "0" : res;
    }
};

