static int cmpStr(const void* a, const void* b) {
    char ab[32], ba[32];
    sprintf(ab, "%d%d", *(const int*)a, *(const int*)b);
    sprintf(ba, "%d%d", *(const int*)b, *(const int*)a);
    return strcmp(ab, ba) > 0 ? -1 : strcmp(ab, ba) < 0 ? 1 : 0;
}
char* largestNumber(int* nums, int n) {
    qsort(nums, n, sizeof(int), cmpStr);
    char* res = malloc(n * 12);
    res[0] = 0;
    for (int i = 0; i < n; i++) { char t[16]; sprintf(t, "%d", nums[i]); strcat(res, t); }
    if (res[0] == '0') { free(res); return strdup("0"); }
    return res;
}
